// Concept D — forward Scenario & Sensitivity lens for the cash-flow model.
// best/base/worst credit outcomes (net-leverage trajectory + FCF/cash) and an
// adjustable 1-way tornado over a selectable output metric.

import { Fragment, useMemo, useState } from "react";
import { Panel } from "@/components/shared/Panel";
import { CollapseButton } from "@/components/shared/CollapseButton";
import { TextInput } from "@/components/shared/TextInput";
import { StatusGlyph } from "@/components/shared/StatusGlyph";
import type { Model } from "@/lib/reports/model";
import type { DownsidePathway, Fragility } from "@/lib/engine/downsidePathway";
import { scenarioFromNL } from "@/lib/api";
import {
  buildScenarios, FORECAST_YEARS, swingLabel, METRICS,
  type Drivers, type MetricKey, type ScenarioLens, type TornadoBar,
} from "@/lib/model/scenarios";
import { fmtMult2, fmtUsdAcct } from "@/lib/format";
import { ScenarioNetworkPanel } from "./ScenarioNetworkPanel";

// NaN/Infinity-safe (a degenerate projection — interest 0, adj ≤ 0 — renders
// "—" rather than "NaNx" / "$InfinityM"). Same finite display as before.
const fmtX = (v: number) => fmtMult2(v);
const fmtUsd = (v: number) => fmtUsdAcct(v);
const fmtMetric = (v: number, key: MetricKey) =>
  METRICS.find((m) => m.key === key)!.unit === "x" ? fmtX(v) : fmtUsd(v);

const GOOD = "color-mix(in srgb, var(--caos-success) 50%, transparent)";
const BAD = "color-mix(in srgb, var(--caos-critical) 50%, transparent)";

// Fragility is never carried by colour alone — the band word + a glyph travel
// with it (a11y / colourblind-safe, per the design system).
const FRAGILITY: Record<Fragility, { color: string; glyph: string }> = {
  HIGH: { color: "var(--caos-critical)", glyph: "▲" },
  MODERATE: { color: "var(--caos-warning)", glyph: "■" },
  LOW: { color: "var(--caos-success)", glyph: "●" },
};

// Live CP-2B read: the issuer's first-order EBITDA-shock sensitivity (net debt
// held flat). Sits beside the forward forecast lens as the engine's own
// downside fact, not a forecast driver — rendered only when a run produced it.
function DownsideFragility({ downside }: { downside: DownsidePathway }) {
  const f = FRAGILITY[downside.fragility];
  const { breachThresholdX: breach, shockToBreachPct: stb } = downside;
  const val = "tabular text-caos-md text-right";
  const hd = "tabular text-caos-xs uppercase tracking-wide text-right text-caos-muted";
  return (
    <div>
      <div className="flex items-center gap-1.5 mb-1.5">
        <span className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">Downside fragility · CP-2B</span>
        <span className="flex-1" />
        <span
          className="tabular text-caos-3xs px-1 py-px rounded border whitespace-nowrap"
          style={{ color: f.color, borderColor: f.color }}
          title={`First-order EBITDA-shock fragility: ${downside.fragility}`}
        >
          {f.glyph} {downside.fragility}
        </span>
      </div>
      <div className="grid items-center gap-x-2 gap-y-1" style={{ gridTemplateColumns: "1fr repeat(2, 1fr)" }}>
        <span />
        <span className={hd}>Net lev</span>
        <span className={hd}>Int cov</span>

        <span className="text-caos-md text-caos-text">Today</span>
        <span className={val} style={{ color: "var(--caos-text)" }}>{fmtX(downside.currentNetLeverage)}</span>
        <span className={val} style={{ color: "var(--caos-muted)" }}>—</span>

        {downside.shocks.map((s) => (
          <Fragment key={s.shockPct}>
            <span className="flex items-baseline gap-1.5">
              <span className="text-caos-md text-caos-text">EBITDA</span>
              <span className="tabular text-caos-2xs text-caos-muted">−{s.shockPct}%</span>
            </span>
            <span className={val} style={{ color: s.stressedNetLeverage >= breach ? "var(--caos-critical)" : "var(--caos-text)" }}>
              {fmtX(s.stressedNetLeverage)}
            </span>
            <span className={val} style={{ color: "var(--caos-text)" }}>
              {s.stressedCoverage != null ? fmtX(s.stressedCoverage) : "—"}
            </span>
          </Fragment>
        ))}
      </div>
      <div className="tabular text-caos-2xs text-caos-muted leading-snug mt-1.5">
        {stb != null
          ? `A −${stb}% EBITDA decline lifts net leverage to the ${fmtX(breach)} distress marker.`
          : `Net leverage stays below the ${fmtX(breach)} distress marker through a −30% EBITDA decline.`}
        {" "}Net debt held flat — first-order shock, not a cash-sweep path.
      </div>
    </div>
  );
}

function ScenarioComparison({ sc, active }: { sc: ScenarioLens; active?: string | null }) {
  const proj = useMemo(() => sc.scenarios.map((s) => ({ s, p: sc.project(s.drivers) })), [sc]);
  const val = "tabular text-caos-md text-right";
  const lbl = "flex items-baseline gap-1.5 min-w-0";
  const top = " mt-1 pt-1.5 border-t border-caos-border/60";
  return (
    <div>
      <div className="flex items-center gap-1.5 mb-1.5">
        <span className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">
          Best · base · worst — FY26e–FY28e
        </span>
        {active ? (
          <span className="tabular text-caos-3xs px-1 py-px rounded border whitespace-nowrap truncate" style={{ color: "var(--caos-accent)", borderColor: "color-mix(in srgb, var(--tranche-2l) 40%, transparent)", background: "color-mix(in srgb, var(--tranche-2l) 8%, transparent)" }} title={`Re-centered on scenario: ${active}`}>
            ▸ {active}
          </span>
        ) : null}
      </div>
      <div className="grid items-center gap-x-2 gap-y-1" style={{ gridTemplateColumns: "1fr repeat(3, 1fr)" }}>
        <span />
        {proj.map(({ s }) => (
          <span key={s.key} className="tabular text-caos-xs uppercase tracking-wide text-right" style={{ color: s.color }}>{s.label}</span>
        ))}

        {/* net-leverage trajectory */}
        {FORECAST_YEARS.map((yr, i) => (
          <Fragment key={yr}>
            <span className={lbl}>
              <span className="text-caos-md text-caos-text">{i === 0 ? "Net leverage" : ""}</span>
              <span className="tabular text-caos-2xs text-caos-muted">{yr}</span>
            </span>
            {proj.map(({ s, p }) => (
              <span key={s.key} className={val} style={{ color: i === FORECAST_YEARS.length - 1 ? s.color : "var(--caos-text)" }}>
                {fmtX(p.netLev[i])}
              </span>
            ))}
          </Fragment>
        ))}

        {/* cumulative FCF */}
        <span className={lbl + top}>
          <span className="text-caos-md text-caos-text">Cum. FCF</span>
          <span className="tabular text-caos-2xs text-caos-muted">3y</span>
        </span>
        {proj.map(({ s, p }) => (
          <span key={s.key} className={val + top} style={{ color: "var(--caos-text)" }}>
            {fmtUsd(p.fcf.reduce((a, b) => a + b, 0))}
          </span>
        ))}

        {/* minimum cash */}
        <span className={lbl}>
          <span className="text-caos-md text-caos-text">Min cash</span>
          <span className="tabular text-caos-2xs text-caos-muted">3y</span>
        </span>
        {proj.map(({ s, p }) => {
          const mc = Math.min(...p.cash);
          return (
            <span key={s.key} className={val} style={{ color: mc < 0 ? "var(--caos-critical)" : "var(--caos-text)" }}>
              {fmtUsd(mc)}
            </span>
          );
        })}
      </div>
    </div>
  );
}

type MetricMeta = (typeof METRICS)[number];

const tornadoScale = (bars: TornadoBar[], base: number, metric: MetricKey) => {
  const all = [...bars.flatMap((b) => [b.low, b.high]), base];
  const dmin = Math.min(...all), dmax = Math.max(...all), span = dmax - dmin || 1;
  return {
    position: (value: number) => ((value - dmin) / span) * 100,
    format: (value: number) => fmtMetric(value, metric),
  };
};

const tornadoMagnitude = (meta: MetricMeta, value: number): string => {
  if (!Number.isFinite(value)) return "—";
  return meta.unit === "x"
    ? `${Math.abs(value).toFixed(2)}x`
    : `$${Math.round(Math.abs(value)).toLocaleString()}M`;
};

const tornadoSkew = (ratio: number): string => {
  if (ratio >= 1.5) return "markedly downside-skewed";
  if (ratio >= 1.15) return "modestly downside-skewed";
  if (ratio <= 0.67) return "markedly upside-skewed";
  return ratio <= 0.87 ? "modestly upside-skewed" : "roughly symmetric";
};

const tornadoRead = (meta: MetricMeta, bars: TornadoBar[], base: number) => {
  const top = bars[0];
  const range = (bar: TornadoBar) => Math.abs(bar.high - bar.low);
  const worseOf = (bar: TornadoBar) => meta.lowerIsBetter
    ? Math.max(bar.low, bar.high)
    : Math.min(bar.low, bar.high);
  const betterOf = (bar: TornadoBar) => meta.lowerIsBetter
    ? Math.min(bar.low, bar.high)
    : Math.max(bar.low, bar.high);
  const worstValue = worseOf(top);
  const bestValue = betterOf(top);
  const downsideAmount = Math.abs(worstValue - base);
  const upsideAmount = Math.abs(bestValue - base);
  const ratio = upsideAmount === 0 ? Infinity : downsideAmount / upsideAmount;
  const concentration = range(bars[1]) === 0 ? Infinity : range(top) / range(bars[1]);
  return {
    top,
    range,
    worstValue,
    bestValue,
    downsideAmount,
    upsideAmount,
    skew: tornadoSkew(ratio),
    concentration: Number.isFinite(concentration)
      ? `${concentration.toFixed(1)}× the next-widest factor (${bars[1].label})`
      : "far wider than any other factor",
    low: Math.min(top.low, top.high),
    high: Math.max(top.low, top.high),
    adverseDirection: worstValue > base ? "above" : "below",
    favorableDirection: bestValue > base ? "above" : "below",
  };
};

function TornadoMetricSelector({ metric, onChange }: { metric: MetricKey; onChange: (metric: MetricKey) => void }) {
  return (
    <div className="flex flex-wrap gap-1">
      {METRICS.map((item) => (
        <button key={item.key} onClick={() => onChange(item.key)} className={"tabular text-caos-2xs px-1.5 min-h-[24px] inline-flex items-center rounded border transition-caos focus-ring " + (metric === item.key ? "border-caos-accent text-caos-text bg-caos-elevated" : "border-caos-border text-caos-muted hover:text-caos-text")}>
          {item.label}
        </button>
      ))}
    </div>
  );
}

function TornadoIntensitySelector({ intensity, base, format, onChange }: { intensity: number; base: number; format: (value: number) => string; onChange: (intensity: number) => void }) {
  return (
    <div className="flex items-center gap-1.5">
      <span className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">Swing</span>
      {([[0.5, "±½"], [1, "±1"], [1.5, "±1½"]] as const).map(([value, label]) => (
        <button key={value} onClick={() => onChange(value)} title={`Driver swing intensity ×${value}`} className={"tabular text-caos-2xs px-1.5 min-h-[24px] inline-flex items-center rounded border transition-caos focus-ring " + (intensity === value ? "border-caos-accent text-caos-text bg-caos-elevated" : "border-caos-border text-caos-muted hover:text-caos-text")}>
          {label}
        </button>
      ))}
      <span className="flex-1" />
      <span className="tabular text-caos-2xs text-caos-muted">base {format(base)}</span>
    </div>
  );
}

function TornadoBarRow({
  bar,
  base,
  meta,
  position,
  format,
}: {
  bar: TornadoBar;
  base: number;
  meta: MetricMeta;
  position: (value: number) => number;
  format: (value: number) => string;
}) {
  const low = Math.min(bar.low, bar.high);
  const high = Math.max(bar.low, bar.high);
  const lowPosition = position(low);
  const basePosition = position(base);
  const highPosition = position(high);
  const belowColor = meta.lowerIsBetter ? GOOD : BAD;
  const aboveColor = meta.lowerIsBetter ? BAD : GOOD;
  return (
    <div className="flex items-center gap-1.5" title={`${bar.label}: ${format(bar.low)} ↔ ${format(bar.high)} (base ${format(base)})`}>
      <span className="text-caos-xs text-caos-text w-[96px] shrink-0 truncate">{bar.label}</span>
      <span className="tabular text-caos-2xs text-caos-text w-[48px] shrink-0 text-right whitespace-nowrap tabular-nums">{format(low)}</span>
      <div className="relative flex-1 h-3.5 rounded-sm" style={{ background: "var(--caos-bg)" }}>
        <span className="absolute top-0 bottom-0 rounded-l-sm" style={{ left: `${lowPosition}%`, width: `${Math.max(0, basePosition - lowPosition)}%`, background: belowColor }} />
        <span className="absolute top-0 bottom-0 rounded-r-sm" style={{ left: `${basePosition}%`, width: `${Math.max(0, highPosition - basePosition)}%`, background: aboveColor }} />
        <span className="absolute top-[-1px] bottom-[-1px] w-px" style={{ left: `${basePosition}%`, background: "var(--caos-text)" }} />
      </div>
      <span className="tabular text-caos-2xs text-caos-text w-[48px] shrink-0 text-left whitespace-nowrap tabular-nums">{format(high)}</span>
    </div>
  );
}

function TornadoBars({ bars, base, meta, position, format }: { bars: TornadoBar[]; base: number; meta: MetricMeta; position: (value: number) => number; format: (value: number) => string }) {
  return <div className="flex flex-col gap-1.5">{bars.map((bar) => <TornadoBarRow key={bar.driver} bar={bar} base={base} meta={meta} position={position} format={format} />)}</div>;
}

function TornadoNarrative({
  bars,
  base,
  meta,
  intensity,
  format,
}: {
  bars: TornadoBar[];
  base: number;
  meta: MetricMeta;
  intensity: number;
  format: (value: number) => string;
}) {
  const read = tornadoRead(meta, bars, base);
  const magnitude = (value: number) => tornadoMagnitude(meta, value);
  return (
    <div className="flex flex-col gap-1 pt-2 border-t border-caos-border/60">
      <div className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">Sensitivity read</div>
      <p className="text-caos-md text-caos-muted leading-relaxed">
        <span className="font-medium text-caos-text">{read.top.label} is the binding lever.</span>{" "}
        A {swingLabel(read.top.driver, intensity)} swing alone moves the outcome{" "}
        <span className="tabular text-caos-text">{format(read.low)}–{format(read.high)}</span>{" "}({magnitude(read.range(read.top))}), {read.concentration}.{" "}
        Risk is {read.skew}: the adverse case (<span className="tabular text-caos-text">{format(read.worstValue)}</span>){" "}
        sits {magnitude(read.downsideAmount)} {read.adverseDirection} the {format(base)} base versus {magnitude(read.upsideAmount)} {read.favorableDirection} on the upside.{" "}
        {bars[2].label} and {bars[3].label} are second-order (≤{magnitude(read.range(bars[2]))} each).{" "}
        Debt is held static — FCF accrues to cash, so this is a deleveraging lens, not a valuation.
      </p>
    </div>
  );
}

function Tornado({ sc }: { sc: ScenarioLens }) {
  const [metric, setMetric] = useState<MetricKey>("netLevExit");
  const [intensity, setIntensity] = useState(1);
  const meta = METRICS.find((item) => item.key === metric)!;
  const { base, bars } = useMemo(() => sc.tornado(metric, intensity), [sc, metric, intensity]);
  const scale = tornadoScale(bars, base, metric);

  return (
    <div className="flex flex-col gap-2">
      <div className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">Sensitivity — tornado</div>
      <TornadoMetricSelector metric={metric} onChange={setMetric} />
      <TornadoIntensitySelector intensity={intensity} base={base} format={scale.format} onChange={setIntensity} />
      <TornadoBars bars={bars} base={base} meta={meta} position={scale.position} format={scale.format} />

      <div className="tabular text-caos-2xs text-caos-muted leading-snug">
        {meta.lowerIsBetter ? "Green improves (lower), red worsens." : "Green improves (higher), red worsens."} Bar spans low–high outcome; tick = {scale.format(base)} base.
      </div>
      <TornadoNarrative bars={bars} base={base} meta={meta} intensity={intensity} format={scale.format} />
    </div>
  );
}

// ── Scenario builder ─────────────────────────────────────────────────────────
interface ActiveScenario { label: string; rationale: string; deltas: Partial<Drivers> }

// Pre-defined scenarios — deterministic driver deltas (Drivers units: pp as
// fractions, rate as a fraction). Parallel the issuer-Q&A starter chips.
const PRESETS: { label: string; deltas: Partial<Drivers> }[] = [
  { label: "Energy price spike", deltas: { adjMargin: -0.03, rate: 0.005 } },
  { label: "Rate hike +200bps", deltas: { rate: 0.02 } },
  { label: "Demand recession", deltas: { revGrowth: -0.05, adjMargin: -0.02 } },
  { label: "Margin compression", deltas: { adjMargin: -0.025 } },
  { label: "Capex surge", deltas: { capexPct: 0.02 } },
];

const DRIVER_LABEL: Record<keyof Drivers, string> = {
  revGrowth: "rev growth", adjMargin: "margin", capexPct: "capex", rate: "rate",
};
function fmtDelta(key: keyof Drivers, v: number): string {
  const sign = v >= 0 ? "+" : "−";
  if (key === "rate") return `${sign}${Math.round(Math.abs(v) * 10000)}bps rate`;
  return `${sign}${parseFloat((Math.abs(v) * 100).toFixed(2))}pp ${DRIVER_LABEL[key]}`;
}
function deltaSummary(d: Partial<Drivers>): string {
  return (["revGrowth", "adjMargin", "capexPct", "rate"] as (keyof Drivers)[])
    .filter((k) => d[k]).map((k) => fmtDelta(k, d[k] as number)).join(" · ");
}

function ScenarioBuilder({
  active, onApply, onReset,
}: {
  active: ActiveScenario | null;
  onApply: (deltas: Partial<Drivers>, label: string, rationale: string) => void;
  onReset: () => void;
}) {
  const [q, setQ] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState<string | null>(null);

  const runNL = async (text?: string) => {
    const t = (text ?? q).trim();
    if (!t || busy) return;
    setBusy(true); setErr(null);
    try {
      const s = await scenarioFromNL(t);
      const deltas: Partial<Drivers> = {};
      if (s.rev_growth_delta) deltas.revGrowth = s.rev_growth_delta;
      if (s.margin_delta) deltas.adjMargin = s.margin_delta;
      if (s.capex_delta) deltas.capexPct = s.capex_delta;
      if (s.rate_delta) deltas.rate = s.rate_delta;
      onApply(deltas, s.label || t, s.rationale || "");
      setQ("");
    } catch (e) {
      const d = (e as { response?: { data?: { detail?: string } }; message?: string })?.response?.data?.detail
        || (e as Error)?.message || "couldn't build that scenario";
      setErr(String(d));
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="flex flex-col gap-2">
      <div className="tabular text-caos-2xs uppercase tracking-wider text-caos-muted">Scenario builder</div>

      {active ? (
        <div className="rounded border px-2 py-1.5 flex flex-col gap-1" style={{ borderColor: "color-mix(in srgb, var(--tranche-2l) 40%, transparent)", background: "color-mix(in srgb, var(--tranche-2l) 8%, transparent)" }}>
          <div className="flex items-center gap-1.5">
            <span className="w-1.5 h-1.5 rounded-sm shrink-0" style={{ background: "var(--caos-accent)" }} />
            <span className="text-caos-md text-caos-text font-medium truncate">{active.label}</span>
            <span className="flex-1" />
            <button onClick={onReset} title="Revert to module forecasts" className="tabular text-caos-2xs px-1.5 min-h-[24px] inline-flex items-center rounded border border-caos-border text-caos-muted hover:text-caos-text hover:border-caos-accent/60 transition-caos focus-ring whitespace-nowrap">↶ RESET</button>
          </div>
          <div className="tabular text-caos-xs" style={{ color: "var(--caos-accent)" }}>{deltaSummary(active.deltas) || "no driver change"}</div>
          {active.rationale ? <div className="text-caos-xs text-caos-muted leading-snug">{active.rationale}</div> : null}
        </div>
      ) : (
        <div className="tabular text-caos-xs text-caos-muted leading-snug">Apply a scenario to re-center base &amp; downside. Module forecasts shown.</div>
      )}

      {/* pre-defined scenarios */}
      <div className="flex flex-wrap gap-1">
        {PRESETS.map((p) => (
          <button
            key={p.label}
            onClick={() => onApply(p.deltas, p.label, "")}
            title={deltaSummary(p.deltas)}
            className="tabular text-caos-2xs px-1.5 min-h-[24px] inline-flex items-center rounded border border-caos-border text-caos-muted hover:text-caos-text hover:border-caos-accent/60 transition-caos focus-ring"
          >
            {p.label}
          </button>
        ))}
      </div>

      {/* natural-language scenario */}
      <div className="flex items-center gap-1.5">
        <span className="text-caos-accent text-caos-xl">✦</span>
        <TextInput
          name="scenario-description"
          autoComplete="off"
          value={q}
          onChange={(e) => setQ(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); runNL(); } }}
              placeholder="Describe a scenario — e.g. oil shock, margins compress 200 bps…"
          aria-label="Describe a scenario"
          maxLength={500}
          className="flex-1 px-2 py-1 text-caos-md"
        />
        <button
          onClick={() => runNL()}
          disabled={busy || !q.trim()}
          className="shrink-0 tabular text-caos-xs px-2 py-1 rounded transition-caos disabled:opacity-40"
          style={{ background: "var(--caos-accent)", color: "var(--caos-bg)" }}
        >
          {busy ? "…" : "BUILD"}
        </button>
      </div>
      {err ? (
        <div className="tabular text-caos-xs flex items-start gap-1" style={{ color: "var(--caos-warning)" }}>
          <span className="shrink-0"><StatusGlyph kind="warning" /></span>
          <span className="min-w-0 max-h-16 overflow-y-auto break-words leading-snug">{err}</span>
        </div>
      ) : null}
    </div>
  );
}

// Derived from the model's assumptions-adjusted forecast: base = the BASE
// columns, worst = the DOWNSIDE columns, so both the base- and downside-case
// Assumptions sliders re-center the lens (best/base/worst + tornado). The
// Scenario Builder layers a custom scenario on top; Reset reverts to it.
//
// BY DESIGN: a BASE-case driver edit re-derives BEST and BASE but NOT WORST.
// worst reads the DOWNSIDE columns (d0/d1/d2) in buildScenarios(); best/base
// read the BASE columns (b0/b1/b2). worst therefore owns its own downside
// drivers and is independent of base-case nudges (only downside-case sliders
// and the Scenario Builder deltas — layered onto both cases — move it). This is
// correct, not a stale column.
export function ScenarioPanel({ model, downside, downsideState = "unavailable", issuerId = "", runId = null, onCollapse }: { model: Model; downside?: DownsidePathway | null; downsideState?: "ready" | "unavailable" | "error"; issuerId?: string; runId?: string | null; onCollapse?: () => void }) {
  const [active, setActive] = useState<ActiveScenario | null>(null);
  const [mode, setMode] = useState<"model" | "network">("model");
  const sc = useMemo(() => buildScenarios(model, active?.deltas), [model, active]);
  return (
    <Panel
      title="Scenario & Sensitivity · forward cash-flow lens"
      className="w-[372px] shrink-0"
      right={onCollapse ? (
        <CollapseButton direction="right" label="Collapse Scenario panel" onClick={onCollapse} />
      ) : undefined}
    >
      <div className="p-2.5 flex flex-col gap-3.5">
        <div role="tablist" aria-label="Scenario mode" className="grid grid-cols-2 gap-1 rounded border border-caos-border bg-caos-bg p-1">
          <button type="button" role="tab" aria-selected={mode === "model"} onClick={() => setMode("model")} className={mode === "model" ? "caos-action-primary focus-ring" : "caos-action-secondary focus-ring"}>Model scenario</button>
          <button type="button" role="tab" aria-selected={mode === "network"} onClick={() => setMode("network")} className={mode === "network" ? "caos-action-primary focus-ring" : "caos-action-secondary focus-ring"}>Cross-module propagation</button>
        </div>
        <div hidden={mode !== "model"} className="grid gap-3.5">
          <p className="text-caos-xs leading-relaxed text-caos-muted">Temporary model-case deltas recalculate this cash-flow lens only. They are not saved to the model.</p>
          <ScenarioComparison sc={sc} active={active?.label ?? null} />
          {downside ? (
            <>
              <div className="border-t border-caos-border" />
              <DownsideFragility downside={downside} />
            </>
          ) : (
            <div role={downsideState === "error" ? "alert" : "status"} className="rounded border border-caos-border px-2 py-2 text-caos-xs text-caos-muted">
              <span className="tabular uppercase tracking-wider text-caos-warning">△ Downside fragility · CP-2B unknown</span>
              <p className="mt-1">{downsideState === "error" ? "The optional CP-2B read failed; no all-clear inference is available." : "This run did not establish a CP-2B downside pathway."}</p>
            </div>
          )}
          <div className="border-t border-caos-border" />
          <Tornado sc={sc} />
          <div className="border-t border-caos-border" />
          <ScenarioBuilder
            active={active}
            onApply={(deltas, label, rationale) => setActive({ deltas, label, rationale })}
            onReset={() => setActive(null)}
          />
        </div>
        <div hidden={mode !== "network"}>
          <p className="text-caos-xs leading-relaxed text-caos-muted">Propagates EBITDA and rate shocks through one exact completed analytical run. It never mutates model inputs or reports.</p>
          <ScenarioNetworkPanel issuerId={issuerId} runId={runId} />
        </div>
      </div>
    </Panel>
  );
}
